// Get the items from the previous node
const items = $input.all();
const result =[];

for (const item of items) {
  // Usually, the HTTP Request node outputs string data into "item.json.data"
  // Adjust this property if your HTML is stored under a different key.
  const html = item.json.data || item.json; 

  if (typeof html !== 'string') {
    continue;
  }

  // The HTML uses '<div id="divTrailer_X"' as a container for each movie section.
  // We split the HTML string by this to process one movie at a time.
  const blocks = html.split('<div id="divTrailer_').slice(1);

  // Helper function to strip HTML tags and normalize extra spaces
  const stripTags = (str) => {
      return str.replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
  };

  for (const block of blocks) {
    // 1. Extract Title and URL
    const titleMatch = block.match(/<div class="schedine-titolo">[\s\S]*?<a href="([^"]+)"[^>]*>([^<]+)<\/a>/);
    if (!titleMatch) continue; // Skip if no title is found in this block

    const url = titleMatch[1].trim();
    const title = titleMatch[2].trim();

    // 2. Extract Details (Description, Genre, Country, Year, Duration)
    const detailsMatch = block.match(/<div class="mm-line-height-130 schedine-lancio">([\s\S]*?)<\/div>/);
    let details = "";
    if (detailsMatch) {
        details = stripTags(detailsMatch[1]);
    }

    // 3. Extract Director(s)
    const directorMatch = block.match(/Un film di\s+([\s\S]*?)\./);
    let director = "";
    if (directorMatch) {
        director = stripTags(directorMatch[1]);
    }

    // 4. Extract Cast
    const castMatch = block.match(/<span>Con\s+([\s\S]*?)<\/span>/);
    let cast = "";
    if (castMatch) {
        cast = stripTags(castMatch[1]);
    }

    // 5. Extract Cinemas and Showtimes
    // The class 'mm-light-grey' wraps the block detailing the cinema and showtimes
    const cinemaBlocks = block.split('class="mm-light-grey"').slice(1);
    const cinemas =[];

    for (const cBlock of cinemaBlocks) {
        // Find cinema name
        const cinemaNameMatch = cBlock.match(/<div style="padding-top:3px; float:left; font-weight:600;">([^<]+)<\/div>/);
        let cinemaName = cinemaNameMatch ? cinemaNameMatch[1].trim() : "Sconosciuto";

        // Clean up the word "CINEMA " from the beginning of the name if it exists
        cinemaName = cinemaName.replace(/^CINEMA\s+/i, '');

        // Find all showtimes for this specific cinema
        const timeRegex = /<span class="mm-medium mm-weight-700">([^<]+)<\/span>/g;
        const times =[];
        let tMatch;

        while ((tMatch = timeRegex.exec(cBlock)) !== null) {
            times.push(tMatch[1].trim());
        }

        // Only add if we found a valid name or times
        if (cinemaName !== "Sconosciuto" || times.length > 0) {
            cinemas.push({
                name: cinemaName,
                times: times
            });
        }
    }

    // Prepare the final item to return to n8n
    result.push({
        json: {
            title: title,
            cast: cast,
            details: details,
            cinemas: cinemas
        }
    });
  }
}

// Return the extracted items so subsequent nodes can process them one by one
return result;

// 1. Inserisci qui la tua API Key di TMDB
const TMDB_API_KEY = 'YOUR_API_KEY';

// 2. n8n prende tutti i dati in ingresso tramite $input.all()
const items = $input.all();

// 3. Iteriamo su tutti i film in arrivo
for (const item of items) {
  // I dati veri e propri in n8n risiedono sempre dentro la proprietà "json"
  const movie = item.json;
  const title = movie.title;

  // Estraiamo l'anno dalla descrizione (es. 2026) per usarlo come eventuale fallback
  const yearMatch = movie.details ? movie.details.match(/\b(19|20)\d{2}\b/) : null;
  const year = yearMatch ? yearMatch[0] : '';

  try {
    // --- PRIMO TENTATIVO: SOLO TITOLO ---
    let searchUrl = `https://api.themoviedb.org/3/search/movie?api_key=${TMDB_API_KEY}&query=${encodeURIComponent(title)}&language=it-IT`;

    let searchResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: searchUrl,
      json: true 
    });

    // --- SECONDO TENTATIVO: TITOLO + ANNO ---
    // Se la prima ricerca non ha prodotto risultati e abbiamo estratto l'anno, riproviamo
    if ((!searchResponse.results || searchResponse.results.length === 0) && year) {
      let searchUrlWithYear = `${searchUrl}&primary_release_year=${year}`;
      searchResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: searchUrlWithYear,
        json: true 
      });
    }

    // 5. Se ci sono risultati, arricchiamo il JSON originale
    if (searchResponse.results && searchResponse.results.length > 0) {
      const tmdbMatch = searchResponse.results[0];
      const tmdbId = tmdbMatch.id;

      // Salviamo le info base prese dalla ricerca
      movie.tmdb_id = tmdbId;
      movie.tmdb_title = tmdbMatch.title;
      movie.original_title = tmdbMatch.original_title;
      movie.overview = tmdbMatch.overview;
      movie.release_date = tmdbMatch.release_date;
      movie.vote_average = tmdbMatch.vote_average;
      movie.poster_url = tmdbMatch.poster_path ? `https://image.tmdb.org/t/p/w500${tmdbMatch.poster_path}` : null;

      // --- RECUPERO DETTAGLI ESTESI (GENERI + REGISTA) ---
      try {
        // Usiamo append_to_response=credits per prendere sia i dettagli (generi) sia la crew in una sola chiamata
        const detailsUrl = `https://api.themoviedb.org/3/movie/${tmdbId}?api_key=${TMDB_API_KEY}&append_to_response=credits&language=it-IT`;

        const detailsResponse = await this.helpers.httpRequest({
          method: 'GET',
          url: detailsUrl,
          json: true
        });

        // 1. Recuperiamo i GENERI
        if (detailsResponse.genres && detailsResponse.genres.length > 0) {
           movie.genres = detailsResponse.genres.map(g => g.name).join(', ');
        } else {
           movie.genres = null;
        }

        // 2. Recuperiamo il REGISTA
        if (detailsResponse.credits && detailsResponse.credits.crew) {
            const directors = detailsResponse.credits.crew.filter(person => person.job === 'Director');
            movie.director = directors.length > 0 ? directors.map(d => d.name).join(', ') : null;
        } else {
            movie.director = null;
        }

      } catch (detailsError) {
        // Se fallisce il recupero dettagli, impostiamo null ma teniamo i dati base
        movie.genres = null;
        movie.director = null;
        movie.details_error = detailsError.message;
      }
      // --- FINE SEZIONE DETTAGLI ---

    } else {
      // Se non trova niente né col primo né col secondo tentativo
      movie.tmdb_id = null;
      movie.director = null;
      movie.genres = null;
    }
  } catch (error) {
    // Gestione errori globale
    movie.tmdb_id = null;
    movie.director = null;
    movie.genres = null;
    movie.error = error.message;
  }
}

// 6. Restituisce gli elementi arricchiti al nodo successivo
return items;

// Funzione ultra-compatta: \s+ elimina in un colpo solo \n, \r, \t e spazi multipli.
// Il controllo 'typeof' evita crash se il campo è undefined o null.
const cleanText = (text) => 
  typeof text === 'string' ? text.replace(/\s+/g, ' ').trim() : "N/A";

// Creiamo l'array mappando direttamente gli input di n8n
const moviesForLLM = $input.all().map(item => {
  const m = item.json;

  return {
    t: m.title,                               // t = title
    d: cleanText(m.director),                 // d = director (NUOVO)
    g: cleanText(m.genres),                   // g = genres (NUOVO)
    c: cleanText(m.cast),                     // c = cast
    p: cleanText(m.overview || m.details),    // p = plot (trama)
    r: m.vote_average || "N/A"                // r = rating (voto)
  };
});

// Generiamo il JSON minimizzato pronto per l'LLM
return[{
  json: {
    llm_payload: JSON.stringify(moviesForLLM),
    total_movies: moviesForLLM.length
  }
}];

