for (const item of $input.all()) {
    const movie = item.json;

    // Format Cinemas list with custom links
    let cinemasHtml = "";
    if (movie.cinemas && Array.isArray(movie.cinemas)) {
        movie.cinemas.forEach(cinema => {
            const timesString = Array.isArray(cinema.times) ? cinema.times.join(", ") : cinema.times;

            // --- Logica per link personalizzati dei Cinema ---
            let cinemaUrl = "";
            const cinemaName = cinema.name ? cinema.name.trim() : "";

            if (cinemaName === "The Space Casamassima") {
                cinemaUrl = "https://www.thespacecinema.it/cinema/casamassima/al-cinema";
            } else if (cinemaName === "Splendor") {
                cinemaUrl = "https://www.cinemasplendor.eu/";
            } else if (cinemaName === "Abc") {
                cinemaUrl = "https://www.facebook.com/Cinemabcbari/";
            } else if (cinemaName === "Uci Cinemas Showville") {
                cinemaUrl = "https://ucicinemas.it/cinema/uci-cinemas-showville-bari";
            } else if (cinemaName === "Il Piccolo") {
                cinemaUrl = "https://www.cinemapiccolo.it/";
            } else if (cinemaName === "Galleria") {
                cinemaUrl = "https://www.multicinemagalleria.it/programmazione/";
            }

            // Creiamo il nome del cinema (cliccabile o meno in base alla presenza dell'URL)
            const cinemaDisplayName = cinemaUrl 
                ? `<a href="${cinemaUrl}" target="_blank" style="color: #2980b9; text-decoration: none;">${cinemaName}</a>`
