          GitHub ⭐
        </a>
      </p>

      <p style="margin: 0; font-family: monospace; color: #bdc3c7;">
        v1.2
      </p>

    </div>
    <!-- Fine Footer -->
  </div>
</body>
</html>
`;

// 4. Return ONE single item containing the final HTML
